import json

lines = open('ios_crash.ips').readlines()
body_text = ''.join(lines[1:])
body_text = body_text.replace('\"vmregioninfo\"', '\"vmregioninfo_lower\"')
crash = json.loads(body_text)
images = crash.get('usedImages', [])

# lastExceptionBacktrace - it might be a list of frames directly
leb = crash.get('lastExceptionBacktrace')
if leb:
    if isinstance(leb, list):
        frames = leb
    elif isinstance(leb, dict):
        frames = leb.get('frames', [])
    else:
        frames = []
    for i, f in enumerate(frames[:30]):
        idx = f.get('imageIndex')
        offset = f.get('imageOffset')
        if idx is not None and idx < len(images):
            img = images[idx]
            name = img.get('name', '?')
            base = img.get('base', 0)
            addr = hex(base + offset) if offset else '?'
            print(f'  #{i:2d}  {name:45s}  {addr}')
        else:
            print(f'  #{i:2d}  (unknown image)')
else:
    print('(none)')
